---@type LDisplayBase
local LDisplayBase = LDisplayBase
---@class LDisplayEffect:LDisplayBase
local LDisplayEffect = LxClass("LDisplayEffect",LDisplayBase)
-----------------------------------------------------------------
local typeof = typeof
local typeofTrailRenderer = typeof(UnityEngine.TrailRenderer)
local typeofParticleSystem = typeof(UnityEngine.ParticleSystem)
local typeofRenderer = typeof(UnityEngine.Renderer)
local ParticleScalingMode = UnityEngine.ParticleSystemScalingMode
local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)
local typeOfSkeletonAnimation = typeof(Spine.Unity.SkeletonAnimation)
local typeofAnimator = typeof(UnityEngine.Animator)

local typeOfBoneFollower = typeof(Spine.Unity.BoneFollower)
local typeOfBoneFollowerGraphic = typeof(Spine.Unity.BoneFollowerGraphic)

-----------------------------------------------------------------

function LDisplayEffect:LDisplayEffect()
	self._bVisible = true
	self._effectName = nil
end

function LDisplayEffect:CreateEffect(parentTrans,effectName)
	if string.isempty(effectName) then
		if LOG_INFO_ENABLED then
			print("<color=red>----------------effectName is nil</color>")
		end
		return false
	end

	if not CS.IsValidObject(parentTrans) then
		if LOG_INFO_ENABLED then
			print("<color=red>----------------parentTrans is nil</color>")
		end
		return false
	end

	self._effectName = effectName
	-- 特效多语言
	effectName = gLGameLanguage:GetPrefabName(effectName)
	local pathName = LxResPathUtil.GetEffectPath(effectName)
	if(string.isempty(pathName)) then
		return false
	end

	local assetPath = pathName .. "/" .. effectName
	assetPath = CS.ResPath(CS.RES_ANY_PREFAB, assetPath)

	self:Create(parentTrans,assetPath,effectName, "GameObject", "GameObject")
	return true
end

function LDisplayEffect:CreateImpl(parentTrans,effectName)
	return self:CreateEffect(parentTrans,effectName)
end

function LDisplayEffect:StartLoadEffect()
	self:StartLoad()
end

function LDisplayEffect:ClearTrailRender()
	if not self:IsDpValid() then return end
	local trailRendererList = self:GetTrailRendererList() or {}
	for k,v in ipairs(trailRendererList) do
		v:Clear()
	end
end

function LDisplayEffect:OnCreate()

end

function LDisplayEffect:OnDestroy()
end

---z准备完成
function LDisplayEffect:OnDpReady()
	LDisplayBase.OnDpReady(self)
	self:UpdateVisible()
	self:UpdateSortingLayer()
	self:UpdateEffectRotation()
	self:UpdateAnimatorSpeed()
end

---@param spineDp LDisplaySpine
function LDisplayEffect:InternalInitBoneFollowerGraphic(spineDp,boneName)
	local effectTrans = self:GetDisplayTrans()
	if not effectTrans then return end

	if not spineDp:FindBoneNode(nil,boneName) then
		if LOG_INFO_ENABLED then
			print("模型中没有改骨骼 : " ..tostring(boneName))
		end
		return
	end
	
	local obj = effectTrans.gameObject
	local boneFollower = effectTrans:GetComponent(typeOfBoneFollowerGraphic)
	if not boneFollower then
		boneFollower = obj:AddComponent(typeOfBoneFollowerGraphic)
	end
	local skeletonAni = spineDp:GetSkeletonAnimation()
	if boneFollower and skeletonAni then
		boneFollower.followSkeletonFlip = false
		boneFollower.SkeletonGraphic = skeletonAni
		boneFollower:SetBone(boneName)
	end
	self._displayTrans = obj.transform
end

function LDisplayEffect:InternalInitBoneFollower(spineDp,boneName)
	local effectTrans = self:GetDisplayTrans()
	if not effectTrans then return end

	if not spineDp:FindBoneNode(nil,boneName) then
		if LOG_INFO_ENABLED then
			print("模型中没有改骨骼 : " ..tostring(boneName))
		end
		return
	end

	local boneFollower = effectTrans:GetComponent(typeOfBoneFollower)
	if not boneFollower then
		boneFollower = effectTrans.gameObject:AddComponent(typeOfBoneFollower)
	end
	local skeletonAni = spineDp:GetSkeletonAnimation()
	if boneFollower and skeletonAni then
		boneFollower.SkeletonRenderer = skeletonAni
		boneFollower:SetBone(boneName)
	end
end

function LDisplayEffect:SetVisible(bVisible)
	bVisible = bVisible and true or false
	if self._bVisible == bVisible then return end
	self._bVisible = bVisible
	--if not self:IsDpValid() then return end
	self:UpdateVisible()
end

function LDisplayEffect:UpdateVisible()
	if not self:IsDpValid() then return end
	CS.ShowObject(self:GetDisplayTrans(), self._bVisible)

	if self._onVisibleCall then
		self._onVisibleCall(self,self._bVisible)
	end
end
--------------------------------------------------------------------------------
-- 设置特效的缩放
-- 只可以设置一次，不能还原缩放值，因为原有缩放值丢失了
function LDisplayEffect:SetEffectScale(scaleSize, scale)
	scaleSize = scaleSize or 640
	local dpTrans = self:GetDisplayTrans()
	if not scale then
		scale = Vector3(scaleSize, scaleSize, scaleSize)
	end
	local particleSystemList = self:GetParticleSystemList() or {}
	local particleSystemLen = #particleSystemList
	for k = 1, particleSystemLen do
		local particleSystem = particleSystemList[k]
		particleSystem.main.scalingMode = ParticleScalingMode.Hierarchy
	end
	dpTrans.localScale = scale
end
--------------------------------------------------------------------------------
-- 设置特效的旋转
function LDisplayEffect:SetEffectRotation(rotation)
	if not rotation then return end
	self._rotation = rotation
	self:UpdateEffectRotation()
end

function LDisplayEffect:UpdateEffectRotation()
	if not self._rotation then return end
	if not self:IsDpValid() then return end
	local dpTrans = self:GetDisplayTrans()
	dpTrans.localRotation = self._rotation
end
--------------------------------------------------------------------------------
-- 设置特效的层级
function LDisplayEffect:SetRenderLayer(layerName)
	if string.isempty(layerName) then
		return
	end
	if self._rendererLayerName == layerName then
		return
	end

	self._rendererLayerName = layerName


	self:UpdateSortingLayer()

end

function LDisplayEffect:UpdateSortingLayer()

	if string.isempty(self._rendererLayerName) then
		return
	end

	if not self:IsDpValid() then
		return
	end

	if not self._isInitRendererInfo then
		self:InitRendererInfo()
	end

	local rendererList = self:GetRendererList() or {}
	local rendererLen = #rendererList
	for k = 1, rendererLen do
		local renderer = rendererList[k]
		renderer.sortingLayerName = self._rendererLayerName
	end
end

function LDisplayEffect:SetOnVisibleCall(callback)
	self._onVisibleCall = callback
end
--------------------------------------------------------------------------------
function LDisplayEffect:InitRendererInfo()
	if not self:IsDpValid() then return end

	if self._isInitRendererInfo then return end

	self._isInitRendererInfo = true
	self._rendererLayerList = {}
	self._rendererOrderList = {}
	local rendererList = self:GetRendererList() or {}
	for k,renderer in ipairs(rendererList) do
		self._rendererLayerList[k] = renderer.sortingLayerName
		local order = renderer.sortingOrder
		self._rendererOrderList[k] = order == 0 and 1 or order
	end
end

function LDisplayEffect:ResetRendererInfo()
	if not self._isInitRendererInfo then return end

	local rendererList = self:GetRendererList()
	for k,renderer in ipairs(rendererList) do
		renderer.sortingLayerName = self._rendererLayerList[k]
		renderer.sortingOrder = self._rendererOrderList[k]
	end
end

function LDisplayEffect:ClearOldPlayState()
	local dpTrans = self:GetDisplayTrans()
	if not CS.IsValidObject(dpTrans) then
		return
	end

	local animatorList = self:GetAnimatorList() or {}
	local animatorLen = #animatorList
	for k = 1, animatorLen do
		local animator = animatorList[k]
		animator.enabled = false
	end

	local particleSystemList = self:GetParticleSystemList() or {}
	local particleSystemLen = #particleSystemList
	for k = 1, particleSystemLen do
		local particleSystem = particleSystemList[k]
		particleSystem:Stop()
	end
end

function LDisplayEffect:ResetPlayState(setUnscale)
	local trailRendererList = self:GetTrailRendererList() or {}
	for k,v in ipairs(trailRendererList) do
		v:Clear()
	end

	local mode = nil
	if setUnscale then
		mode = 2
	end

	local animatorList = self:GetAnimatorList() or {}
	local animatorLen = #animatorList
	for k = 1, animatorLen do
		local animator = animatorList[k]
		animator.enabled = true
		if mode then
			PJXUtil.SetAnimatorUpdateMode(animator,mode)
		end
	end

	local particleSystemList = self:GetParticleSystemList() or {}
	local particleSystemLen = #particleSystemList
	for k = 1, particleSystemLen do
		local particleSystem = particleSystemList[k]
		particleSystem:Play()
		if setUnscale ~= nil then
			particleSystem.main.useUnscaledTime = setUnscale
		end
	end

	local skeletonAniList = self:GetSkeletonAniList() or {}
	local skeletonAniLength = #skeletonAniList
	for k= 1,skeletonAniLength do
		local skeletonAni = skeletonAniList[k]
		local aniName = skeletonAni.AnimationName
		local animationState = skeletonAni.AnimationState
		skeletonAni.UnscaledTime = setUnscale or false
		if animationState and aniName then
			animationState:SetAnimation(0, aniName, false)
		end
	end
end

function LDisplayEffect:SetSpeed(speed)
	self._speed = speed
	if not self:IsDpValid() then return end
	self:UpdateAnimatorSpeed()
end

function LDisplayEffect:UpdateAnimatorSpeed()
	if not self._speed then return end
	local animatorList = self:GetAnimatorList() or {}
	local animatorLen = #animatorList
	for k = 1, animatorLen do
		local animator = animatorList[k]
		animator.speed = self._speed
	end

	local particleSystemList = self:GetParticleSystemList() or {}
	local particleSystemLen = #particleSystemList
	for k = 1, particleSystemLen do
		local particleSystem = particleSystemList[k]
		local mainModule = particleSystem.main
		if mainModule then
			mainModule.simulationSpeed = self._speed
		end
	end
end

function LDisplayEffect:RestartFx()
	if not self:IsDpValid() then return end
	local dpTrans = self:GetDisplayTrans()
	CS.ShowObject(dpTrans,true)
	self:ResetPlayState()
end

function LDisplayEffect:IsVisible()
	return self._bVisible
end

function LDisplayEffect:GetEffectName()
	return self._effectName
end

