function LDisplayEffect:GetAnimatorList()
	if not self:IsDpValid() then return nil end
	if not self._animatorList then
		local trans = self:GetDisplayTrans()
		local cList = trans:GetComponentsInChildren(typeofAnimator, true)
		self._animatorList = cList:ToTable()
	end
	return self._animatorList
end

function LDisplayEffect:GetRendererLayerList()
	return self._rendererLayerList or {}
end

function LDisplayEffect:GetRendererOrderList()
	return self._rendererOrderList or {}
end

function LDisplayEffect:GetRendererList()
	if not self:IsDpValid() then return nil end
	if not self._rendererList then
		local trans = self:GetDisplayTrans()
		local cList = trans:GetComponentsInChildren(typeofRenderer, true)
		self._rendererList = cList:ToTable()
	end
	return self._rendererList
end

function LDisplayEffect:GetTrailRendererList()
	if not self:IsDpValid() then return nil end
	if not self._trailRendererList then
		local trans = self:GetDisplayTrans()
		local cList = trans:GetComponentsInChildren(typeofTrailRenderer, true)
		self._trailRendererList = cList:ToTable()
	end
	return self._trailRendererList
end

function LDisplayEffect:GetSkeletonAniList()
	if not self:IsDpValid() then return nil end
	if not self._skeletonAniList then
		local trans = self:GetDisplayTrans()
		local cList = trans:GetComponentsInChildren(typeOfSkeletonAnimation, true)
		self._skeletonAniList = cList:ToTable()
	end
	return self._skeletonAniList
end

function LDisplayEffect:GetParticleSystemList()
	if not self:IsDpValid() then return nil end
	if not self._particleSystemList then
		local trans = self:GetDisplayTrans()
		local cList = trans:GetComponentsInChildren(typeofParticleSystem, true)
		self._particleSystemList = cList:ToTable()
	end
	return self._particleSystemList
end
------------------------------------------------------------------

function LDisplayEffect:SetRenderOrder(sortingOrder)
	if not self._isInitRendererInfo then
		self:InitRendererInfo()
	end
	local rendererList = self:GetRendererList() or {}
	for k,renderer in ipairs(rendererList) do
		local old = self._rendererOrderList[k] or 0
		renderer.sortingOrder = old + sortingOrder
	end
end


------------------------------------------------------------------

return LDisplayEffect